// App.js - Complete Skin Analysis Frontend
import React, { useState, useRef, useEffect } from 'react';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

function App() {
  const [step, setStep] = useState('intro'); // intro, capture, analyzing, results
  const [capturedImages, setCapturedImages] = useState({});
  const [currentAngle, setCurrentAngle] = useState('front');
  const [stream, setStream] = useState(null);
  const [qualityCheck, setQualityCheck] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  const videoRef = useRef(null);
  const canvasRef = useRef(null);

  const angles = [
    { id: 'front', label: 'Front View', instruction: 'Face camera directly' },
    { id: 'left', label: 'Left Profile', instruction: 'Turn left 45°' },
    { id: 'right', label: 'Right Profile', instruction: 'Turn right 45°' }
  ];

  // Start camera
  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: {
          width: { ideal: 1920 },
          height: { ideal: 1080 },
          facingMode: 'user'
        }
      });

      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }

      setStream(mediaStream);
      setStep('capture');
    } catch (err) {
      setError('Camera access denied. Please allow camera permissions.');
      console.error('Camera error:', err);
    }
  };

  // Stop camera
  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  // Real-time quality check
  useEffect(() => {
    if (step !== 'capture' || !videoRef.current) return;

    const interval = setInterval(async () => {
      try {
        const canvas = canvasRef.current;
        const video = videoRef.current;

        if (!canvas || !video || video.readyState !== 4) return;

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(video, 0, 0);

        canvas.toBlob(async (blob) => {
          const formData = new FormData();
          formData.append('image', blob, 'check.jpg');

          const response = await fetch(`${API_URL}/api/check-quality`, {
            method: 'POST',
            body: formData
          });

          if (response.ok) {
            const data = await response.json();
            setQualityCheck(data);
          }
        }, 'image/jpeg', 0.8);

      } catch (err) {
        console.error('Quality check error:', err);
      }
    }, 2000); // Check every 2 seconds

    return () => clearInterval(interval);
  }, [step]);

  // Capture photo
  const capturePhoto = () => {
    const canvas = canvasRef.current;
    const video = videoRef.current;

    if (!canvas || !video) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0);

    const imageDataUrl = canvas.toDataURL('image/jpeg', 0.95);

    setCapturedImages(prev => ({
      ...prev,
      [currentAngle]: imageDataUrl
    }));

    // Move to next angle or finish
    const currentIndex = angles.findIndex(a => a.id === currentAngle);
    if (currentIndex < angles.length - 1) {
      setCurrentAngle(angles[currentIndex + 1].id);
    } else {
      // All angles captured
      stopCamera();
      analyzeImages();
    }
  };

  // Retake photo
  const retakePhoto = (angleId) => {
    setCapturedImages(prev => {
      const newImages = { ...prev };
      delete newImages[angleId];
      return newImages;
    });
    setCurrentAngle(angleId);
  };

  // Analyze captured images
  const analyzeImages = async () => {
    setStep('analyzing');
    setLoading(true);
    setError(null);

    try {
      // Use front view for analysis
      const frontImage = capturedImages.front;

      if (!frontImage) {
        throw new Error('Front view image is required');
      }

      // Convert base64 to blob
      const response = await fetch(frontImage);
      const blob = await response.blob();

      const formData = new FormData();
      formData.append('image', blob, 'analysis.jpg');

      const analysisResponse = await fetch(`${API_URL}/api/analyze`, {
        method: 'POST',
        body: formData
      });

      if (!analysisResponse.ok) {
        const errorData = await analysisResponse.json();
        throw new Error(errorData.error || 'Analysis failed');
      }

      const data = await analysisResponse.json();
      setAnalysis(data.analysis);
      setStep('results');

    } catch (err) {
      setError(err.message);
      setStep('capture');
    } finally {
      setLoading(false);
    }
  };

  // Reset app
  const reset = () => {
    setCapturedImages({});
    setCurrentAngle('front');
    setAnalysis(null);
    setError(null);
    setQualityCheck(null);
    setStep('intro');
  };

  return (
    <div className="App">
      {/* STEP 1: INTRO */}
      {step === 'intro' && (
        <div className="intro-screen">
          <div className="intro-content">
            <h1>🎨 AI Skin Analysis</h1>
            <p className="subtitle">Get professional skin insights in minutes</p>

            <div className="features">
              <div className="feature">
                <span className="icon">📸</span>
                <h3>Multi-Angle Capture</h3>
                <p>Capture your face from different angles</p>
              </div>
              <div className="feature">
                <span className="icon">🤖</span>
                <h3>AI Analysis</h3>
                <p>Advanced AI detects skin issues</p>
              </div>
              <div className="feature">
                <span className="icon">📊</span>
                <h3>Detailed Report</h3>
                <p>Get personalized recommendations</p>
              </div>
            </div>

            <button className="btn-primary" onClick={startCamera}>
              Start Analysis
            </button>

            <div className="tips">
              <h4>Tips for best results:</h4>
              <ul>
                <li>✓ Good lighting (natural light is best)</li>
                <li>✓ Clean, makeup-free face</li>
                <li>✓ Neutral expression</li>
                <li>✓ Hold camera steady</li>
              </ul>
            </div>
          </div>
        </div>
      )}

      {/* STEP 2: CAPTURE */}
      {step === 'capture' && (
        <div className="capture-screen">
          <div className="capture-header">
            <button className="btn-back" onClick={() => { stopCamera(); reset(); }}>
              ← Back
            </button>
            <h2>Capture Your Face</h2>
            <div className="progress">
              {angles.map((angle, idx) => (
                <div
                  key={angle.id}
                  className={`progress-dot ${capturedImages[angle.id] ? 'completed' : ''} ${currentAngle === angle.id ? 'active' : ''}`}
                />
              ))}
            </div>
          </div>

          <div className="capture-container">
            <div className="video-container">
              <video
                ref={videoRef}
                autoPlay
                playsInline
                muted
                className="video-feed"
              />
              <canvas ref={canvasRef} style={{ display: 'none' }} />

              {/* Face guide overlay */}
              <div className="face-guide">
                <svg viewBox="0 0 200 280" className="guide-svg">
                  <ellipse cx="100" cy="100" rx="70" ry="90" fill="none" stroke="white" strokeWidth="2" strokeDasharray="5,5" opacity="0.5"/>
                  <line x1="100" y1="20" x2="100" y2="180" stroke="white" strokeWidth="1" opacity="0.3"/>
                  <line x1="30" y1="100" x2="170" y2="100" stroke="white" strokeWidth="1" opacity="0.3"/>
                </svg>
              </div>

              {/* Quality indicators */}
              {qualityCheck && (
                <div className="quality-indicators">
                  <div className={`indicator ${qualityCheck.quality.resolution.isGood ? 'good' : 'bad'}`}>
                    <span className="indicator-icon">{qualityCheck.quality.resolution.isGood ? '✓' : '✗'}</span>
                    <span>Resolution</span>
                  </div>
                  <div className={`indicator ${qualityCheck.quality.lighting.isGood ? 'good' : 'bad'}`}>
                    <span className="indicator-icon">{qualityCheck.quality.lighting.isGood ? '✓' : '✗'}</span>
                    <span>Lighting</span>
                  </div>
                  <div className={`indicator ${qualityCheck.quality.sharpness.isGood ? 'good' : 'bad'}`}>
                    <span className="indicator-icon">{qualityCheck.quality.sharpness.isGood ? '✓' : '✗'}</span>
                    <span>Sharpness</span>
                  </div>
                </div>
              )}
            </div>

            <div className="capture-controls">
              <div className="current-angle">
                <h3>{angles.find(a => a.id === currentAngle)?.label}</h3>
                <p>{angles.find(a => a.id === currentAngle)?.instruction}</p>
              </div>

              {qualityCheck && qualityCheck.issues.length > 0 && (
                <div className="quality-issues">
                  {qualityCheck.issues.map((issue, idx) => (
                    <div key={idx} className="issue">⚠️ {issue}</div>
                  ))}
                </div>
              )}

              <button
                className="btn-capture"
                onClick={capturePhoto}
                disabled={qualityCheck && !qualityCheck.quality.overall}
              >
                📸 Capture
              </button>

              {/* Thumbnails */}
              <div className="thumbnails">
                {angles.map(angle => (
                  <div key={angle.id} className="thumbnail">
                    {capturedImages[angle.id] ? (
                      <>
                        <img src={capturedImages[angle.id]} alt={angle.label} />
                        <button
                          className="btn-retake"
                          onClick={() => retakePhoto(angle.id)}
                        >
                          ↻
                        </button>
                      </>
                    ) : (
                      <div className="thumbnail-placeholder">
                        {angle.label}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* STEP 3: ANALYZING */}
      {step === 'analyzing' && (
        <div className="analyzing-screen">
          <div className="analyzing-content">
            <div className="spinner"></div>
            <h2>Analyzing Your Skin...</h2>
            <p>Our AI is examining your facial features</p>
            <div className="analyzing-steps">
              <div className="analyzing-step">✓ Image quality verified</div>
              <div className="analyzing-step active">🔍 Detecting skin issues...</div>
              <div className="analyzing-step">📊 Generating recommendations...</div>
            </div>
          </div>
        </div>
      )}

      {/* STEP 4: RESULTS */}
      {step === 'results' && analysis && (
        <div className="results-screen">
          <div className="results-header">
            <h1>Your Skin Analysis Report</h1>
            <button className="btn-new" onClick={reset}>New Analysis</button>
          </div>

          <div className="results-content">
            {/* Overall Score */}
            <div className="card score-card">
              <h2>Overall Skin Health</h2>
              <div className="score-circle">
                <svg viewBox="0 0 200 200">
                  <circle cx="100" cy="100" r="80" fill="none" stroke="#e0e0e0" strokeWidth="20"/>
                  <circle
                    cx="100"
                    cy="100"
                    r="80"
                    fill="none"
                    stroke={analysis.overallScore >= 70 ? '#4caf50' : analysis.overallScore >= 40 ? '#ff9800' : '#f44336'}
                    strokeWidth="20"
                    strokeDasharray={`${(analysis.overallScore / 100) * 502} 502`}
                    transform="rotate(-90 100 100)"
                  />
                </svg>
                <div className="score-text">
                  <div className="score-number">{analysis.overallScore}</div>
                  <div className="score-label">/100</div>
                </div>
              </div>
              <p className="score-summary">{analysis.summary}</p>
              <div className="skin-type">
                <strong>Skin Type:</strong> {analysis.skinType}
              </div>
            </div>

            {/* Detected Issues */}
            <div className="card">
              <h2>🔍 Detected Issues</h2>
              {analysis.detectedIssues.length > 0 ? (
                <div className="issues-list">
                  {analysis.detectedIssues.map((issue, idx) => (
                    <div key={idx} className={`issue-item severity-${issue.severity}`}>
                      <div className="issue-header">
                        <h3>{issue.issue}</h3>
                        <span className="severity-badge">{issue.severity}</span>
                      </div>
                      <p>{issue.description}</p>
                      {issue.affected_areas && issue.affected_areas.length > 0 && (
                        <div className="affected-areas">
                          <strong>Affected areas:</strong> {issue.affected_areas.join(', ')}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              ) : (
                <p className="no-issues">✨ No significant issues detected. Your skin looks healthy!</p>
              )}
            </div>

            {/* Zone Analysis */}
            <div className="card">
              <h2>📍 Facial Zone Analysis</h2>
              <div className="zones-grid">
                {Object.entries(analysis.zoneAnalysis).map(([zone, data]) => (
                  <div key={zone} className={`zone-card condition-${data.condition}`}>
                    <h3>{zone.replace(/([A-Z])/g, ' $1').trim()}</h3>
                    <div className="zone-score">Score: {data.score}/10</div>
                    <div className="zone-condition">{data.condition}</div>
                    {data.issues && data.issues.length > 0 && (
                      <ul className="zone-issues">
                        {data.issues.map((issue, idx) => (
                          <li key={idx}>{issue}</li>
                        ))}
                      </ul>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Treatment Recommendations */}
            {analysis.treatmentRecommendations && analysis.treatmentRecommendations.length > 0 && (
              <div className="card">
                <h2>💆 Treatment Recommendations</h2>
                <div className="treatments-list">
                  {analysis.treatmentRecommendations.map((treatment, idx) => (
                    <div key={idx} className="treatment-item">
                      <h3>{treatment.treatment}</h3>
                      <p><strong>Purpose:</strong> {treatment.purpose}</p>
                      <p><strong>Frequency:</strong> {treatment.frequency}</p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Home Care Routine */}
            {analysis.homeCareRoutine && (
              <div className="card">
                <h2>🏠 Home Care Routine</h2>
                <div className="routine-grid">
                  <div className="routine-section">
                    <h3>☀️ Morning Routine</h3>
                    <ol>
                      {analysis.homeCareRoutine.morning.map((step, idx) => (
                        <li key={idx}>{step}</li>
                      ))}
                    </ol>
                  </div>
                  <div className="routine-section">
                    <h3>🌙 Evening Routine</h3>
                    <ol>
                      {analysis.homeCareRoutine.evening.map((step, idx) => (
                        <li key={idx}>{step}</li>
                      ))}
                    </ol>
                  </div>
                </div>
              </div>
            )}

            {/* Lifestyle Suggestions */}
            {analysis.lifestyleSuggestions && (
              <div className="card">
                <h2>🌟 Lifestyle Suggestions</h2>
                <div className="lifestyle-grid">
                  {Object.entries(analysis.lifestyleSuggestions).map(([category, suggestions]) => (
                    <div key={category} className="lifestyle-section">
                      <h3>{category.charAt(0).toUpperCase() + category.slice(1)}</h3>
                      <ul>
                        {suggestions.map((suggestion, idx) => (
                          <li key={idx}>{suggestion}</li>
                        ))}
                      </ul>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Progress Timeline */}
            {analysis.progressTimeline && (
              <div className="card">
                <h2>📈 Expected Progress Timeline</h2>
                <div className="timeline">
                  {Object.entries(analysis.progressTimeline).map(([period, changes]) => (
                    <div key={period} className="timeline-item">
                      <div className="timeline-marker"></div>
                      <div className="timeline-content">
                        <h3>{period.replace(/([A-Z])/g, ' $1').trim()}</h3>
                        <p>{changes}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          <div className="results-footer">
            <button className="btn-primary" onClick={reset}>
              Start New Analysis
            </button>
            <button className="btn-secondary" onClick={() => window.print()}>
              📄 Download Report
            </button>
          </div>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-toast">
          <span>⚠️ {error}</span>
          <button onClick={() => setError(null)}>✕</button>
        </div>
      )}
    </div>
  );
}

export default App;
